#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define fr first
#define se second
#define pb push_back
using namespace std;
const LL N = 4e5+5 , Base = 1e9;
const LL Inf = 0x3f3f3f3f3f3f3f3f;
struct node{
    LL opt,l,r,Sid,Eid;
}a[N*8],kuo[N*8];
LL n,q,ans[N*8],s[N*8];
stack<LL> sid,snm;vector<node> g[N*8];
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
LL ls(LL u){return (u<<1);}
LL rs(LL u){return (u<<1|1);}
bool cmp(node d1,node d2){
    if(d1.l!=d2.l)return (d1.l<d2.l);
    if(d1.r!=d2.r)return (d1.r>d2.r);
    if(d1.r<0)return d1.Sid<d2.Sid;
    else return d1.Sid>d2.Sid;
}
void Insert(LL u,LL l,LL r,node D){
    if(D.Sid>r||D.Eid<l)return;
    if(D.Sid<=l&&r<=D.Eid){g[u].pb(D);return;}
    if(l==r)return;LL mid=(l+r)>>1;
    Insert(ls(u),l,mid,D);
    Insert(rs(u),mid+1,r,D);return;
}
void Add(LL u,LL x){sid.push(u),snm.push(s[u]),s[u]=x;return;}
void Update(LL u,LL l,LL r,LL L,LL R,LL x){
    if(r<L||l>R)return;
    if(L<=l&&r<=R){if(s[u]>x)Add(u,x);return;}
    LL mid=(l+r)>>1;Update(ls(u),l,mid,L,R,x);
    Update(rs(u),mid+1,r,L,R,x);return;
}
LL Query(LL u,LL l,LL r,LL P){
    if(r<P||l>P)return Inf;
    if(l==r)return s[u];
    LL mid=(l+r)>>1;
    LL x=Query(ls(u),l,mid,P);
    LL y=Query(rs(u),mid+1,r,P);
    return min(min(x,y),s[u]);
}
void Sol(LL u,LL l,LL r){
    LL sz=sid.size();ans[u]=1;
    for(auto x:g[u]){
        if(Query(1,1,2*q,x.l)!=Query(1,1,2*q,x.r)){ans[u]=0;break;}
        Update(1,1,2*q,x.l,x.r,(x.r-x.l+1)*Base+x.Sid);
    }
    if(l<r){LL mid=(l+r)>>1;
        Sol(ls(u),l,mid),Sol(rs(u),mid+1,r);}
    while(sid.size()>sz){
        s[sid.top()]=snm.top();
        sid.pop(),snm.pop();
    }return;
}
void Print(LL u,LL l,LL r,LL k){
    k&=ans[u];
    if(l==r){cout<<(k?"Yes\n":"No\n");return;}
    LL mid=(l+r)>>1;Print(ls(u),l,mid,k);
    Print(rs(u),mid+1,r,k);return;
}
int main(){
    n=read(),q=read();
    for(LL i=1;i<=q;i++){
        a[i].opt=read();
        if(a[i].opt==1)
            a[i].l=read(),a[i].r=read(),a[i].Sid=i;
        else a[read()].Eid=i;
    }
    for(LL i=1;i<=q;i++)
        kuo[i]={0,a[i].l,a[i].r,a[i].Sid,0},
        kuo[i+q]={0,a[i].r,-Inf+a[i].l,a[i].Sid,0};
    sort(kuo+1,kuo+2*q+1,cmp);
    for(LL i=1;i<=2*q;i++){
        if(!kuo[i].Sid)continue;
        LL x=kuo[i].Sid;
        if(kuo[i].r>=0)a[x].l=i;
        else a[x].r=i;
    }
    for(LL i=1;i<=q;i++){
        if(a[i].opt==2)continue;
        if(!a[i].Eid)a[i].Eid=q;else a[i].Eid--;
        Insert(1,1,q,a[i]);
    }
    memset(s,0x3f,sizeof(s));
    Sol(1,1,q);Print(1,1,q,1);
    return 0;
}
